const { db } = require('../config/database');

class ChatMessage {
  // 创建消息
  static async create(data) {
    const { senderId, channelType, channelId, content, metadata = {}, isSystemMessage = false } = data;
    
    const [message] = await db('chat_messages')
      .insert({
        sender_id: senderId,
        channel_type: channelType,
        channel_id: channelId,
        content,
        metadata: JSON.stringify(metadata),
        is_system_message: isSystemMessage
      })
      .returning('*');
    
    return message;
  }

  // 获取频道消息
  static async getChannelMessages(channelType, channelId, limit = 50, offset = 0) {
    const messages = await db('chat_messages')
      .select(
        'chat_messages.*',
        'users.username as sender_name',
        'users.avatar_url as sender_avatar'
      )
      .join('users', 'chat_messages.sender_id', 'users.id')
      .where({
        'chat_messages.channel_type': channelType,
        'chat_messages.channel_id': channelId
      })
      .orderBy('chat_messages.created_at', 'desc')
      .limit(limit)
      .offset(offset);
    
    return messages.reverse(); // 返回时间正序
  }

  // 获取私聊消息
  static async getPrivateMessages(userId1, userId2, limit = 50, offset = 0) {
    const messages = await db('chat_messages')
      .select(
        'chat_messages.*',
        'users.username as sender_name',
        'users.avatar_url as sender_avatar'
      )
      .join('users', 'chat_messages.sender_id', 'users.id')
      .where('chat_messages.channel_type', 'private')
      .andWhere(function() {
        this.where(function() {
          this.where('chat_messages.channel_id', userId1)
            .andWhere('chat_messages.sender_id', userId2);
        }).orWhere(function() {
          this.where('chat_messages.channel_id', userId2)
            .andWhere('chat_messages.sender_id', userId1);
        });
      })
      .orderBy('chat_messages.created_at', 'desc')
      .limit(limit)
      .offset(offset);
    
    return messages.reverse();
  }

  // 获取未读消息
  static async getUnreadMessages(userId, channelType, channelId, limit = 50, offset = 0) {
    const messages = await db('unread_messages')
      .select(
        'chat_messages.*',
        'users.username as sender_name',
        'users.avatar_url as sender_avatar'
      )
      .join('chat_messages', 'unread_messages.message_id', 'chat_messages.id')
      .join('users', 'chat_messages.sender_id', 'users.id')
      .where({
        'unread_messages.user_id': userId,
        'unread_messages.channel_type': channelType,
        'unread_messages.channel_id': channelId
      })
      .orderBy('chat_messages.created_at', 'asc')
      .limit(limit)
      .offset(offset);
    
    return messages;
  }

  // 标记消息为已读
  static async markAsRead(userId, messageIds) {
    if (!Array.isArray(messageIds) || messageIds.length === 0) {
      return 0;
    }
    
    const deleted = await db('unread_messages')
      .where('user_id', userId)
      .whereIn('message_id', messageIds)
      .del();
    
    return deleted;
  }

  // 创建未读消息记录
  static async createUnreadRecords(messageId, channelType, channelId, excludeUserId = null) {
    let query = db('users').select('id');
    
    // 根据频道类型确定接收者
    if (channelType === 'global') {
      // 全局消息：所有用户
      if (excludeUserId) {
        query = query.whereNot('users.id', excludeUserId);
      }
    } else if (channelType === 'alliance') {
      // 联盟消息：联盟成员
      query = query.join('alliance_members', 'users.id', 'alliance_members.user_id')
        .where('alliance_members.alliance_id', channelId);
      if (excludeUserId) {
        query = query.whereNot('users.id', excludeUserId);
      }
    } else if (channelType === 'private') {
      // 私聊消息：特定用户
      query = query.where('users.id', channelId);
    }
    
    const userIds = await query;
    
    if (userIds.length === 0) {
      return [];
    }
    
    const unreadRecords = userIds.map(user => ({
      user_id: user.id,
      message_id: messageId,
      channel_type: channelType,
      channel_id: channelId
    }));
    
    const inserted = await db('unread_messages')
      .insert(unreadRecords)
      .returning('*');
    
    return inserted;
  }

  // 根据ID查找消息
  static async findById(messageId) {
    const message = await db('chat_messages')
      .select(
        'chat_messages.*',
        'users.username as sender_name',
        'users.avatar_url as sender_avatar'
      )
      .join('users', 'chat_messages.sender_id', 'users.id')
      .where('chat_messages.id', messageId)
      .first();
    
    return message;
  }

  // 删除消息
  static async delete(messageId) {
    await db('chat_messages')
      .where('id', messageId)
      .del();
    
    // 同时删除相关的未读记录
    await db('unread_messages')
      .where('message_id', messageId)
      .del();
    
    return true;
  }

  // 标记消息为已读
  static async markMessagesAsRead(userId, messageIds) {
    if (!Array.isArray(messageIds) || messageIds.length === 0) {
      return 0;
    }
    
    const deleted = await db('unread_messages')
      .where('user_id', userId)
      .whereIn('message_id', messageIds)
      .del();
    
    return deleted;
  }

  // 标记频道为已读
  static async markChannelAsRead(userId, channelType, channelId) {
    const deleted = await db('unread_messages')
      .where({
        'user_id': userId,
        'channel_type': channelType,
        'channel_id': channelId
      })
      .del();
    
    return deleted;
  }

  // 获取未读消息数
  static async getUnreadCount(userId, channelType, channelId) {
    const result = await db('unread_messages')
      .count('* as count')
      .where({
        'user_id': userId,
        'channel_type': channelType,
        'channel_id': channelId
      })
      .first();
    
    return parseInt(result.count);
  }

  // 获取频道统计信息
  static async getChannelStats(channelType, channelId) {
    const stats = await db('chat_messages')
      .select(
        db.raw('COUNT(*) as total_messages'),
        db.raw('COUNT(DISTINCT sender_id) as unique_senders'),
        db.raw('MAX(created_at) as last_message_time')
      )
      .where({
        'channel_type': channelType,
        'channel_id': channelId
      })
      .first();
    
    return {
      total_messages: parseInt(stats.total_messages),
      unique_senders: parseInt(stats.unique_senders),
      last_message_time: stats.last_message_time
    };
  }

  // 搜索消息
  static async searchMessages(channelType, channelId, query, limit = 20, offset = 0) {
    let dbQuery = db('chat_messages')
      .select(
        'chat_messages.*',
        'users.username as sender_name',
        'users.avatar_url as sender_avatar'
      )
      .join('users', 'chat_messages.sender_id', 'users.id')
      .where(function() {
        this.where('chat_messages.content', 'ilike', `%${query}%`)
          .orWhere('users.username', 'ilike', `%${query}%`);
      });
    
    // 根据频道类型过滤
    if (channelType === 'global') {
      dbQuery = dbQuery.where('chat_messages.channel_type', 'global');
    } else if (channelType === 'alliance') {
      // 只能搜索联盟消息
      dbQuery = dbQuery.where('chat_messages.channel_type', 'alliance')
        .where('chat_messages.channel_id', channelId);
    } else if (channelType === 'private') {
      // 只能搜索私聊消息
      dbQuery = dbQuery.where('chat_messages.channel_type', 'private')
        .where('chat_messages.channel_id', channelId);
    }
    
    const messages = await dbQuery
      .orderBy('chat_messages.created_at', 'desc')
      .limit(limit)
      .offset(offset);
    
    return messages;
  }
}

module.exports = ChatMessage;
